1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	const sortCells = (cells: Cell[]): Cell[] =>
5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty input produces empty output", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("two adjacent cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	  it("block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] stays the same", () => {
18	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
20	  });
21	  it("live cell with more than 3 neighbors dies from overpopulation", () => {
22	    // Gen 0: ### / .#. / ### — center (1,1) has 6 live neighbors → must die
23	    const gen0: Cell[] = [
24	      [0, 2], [1, 2], [2, 2],
25	      [1, 1],
26	      [0, 0], [1, 0], [2, 0],
27	    ];
28	    // Center (1,1) must NOT appear in Gen 1
29	    expect(nextGeneration(gen0)).not.toContainEqual([1, 1]);
30	  });
31	  it("dead cell with exactly 3 neighbors becomes alive (reproduction example)", () => {
32	    // Gen 0: ##. / #.. / ...  → Gen 1: ##. / ##. / ...
33	    const gen0: Cell[] = [[0, 2], [1, 2], [0, 1]];
34	    const gen1: Cell[] = [[0, 2], [1, 2], [0, 1], [1, 1]];
35	    expect(sortCells(nextGeneration(gen0))).toEqual(sortCells(gen1));
36	  });
37	  it("blinker oscillates: vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]", () => {
38	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
39	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
40	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(horizontal));
41	  });
42	  it("blinker oscillates back: horizontal [(-1,1),(0,1),(1,1)] → vertical [(0,0),(0,1),(0,2)]", () => {
43	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
44	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
45	    expect(sortCells(nextGeneration(horizontal))).toEqual(sortCells(vertical));
46	  });
47	  it("handles negative coordinates correctly (blinker centered at negative position)", () => {
48	    const vertical: Cell[] = [[-5, -6], [-5, -5], [-5, -4]];
49	    const horizontal: Cell[] = [[-6, -5], [-5, -5], [-4, -5]];
50	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(horizontal));
51	  });
52	});
