1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	type NeighborTally = { cell: Cell; liveNeighborCount: number };
15	
16	const tallyLiveNeighborsPerCandidate = (liveCells: Cell[]): Map<string, NeighborTally> => {
17	  const tallies = new Map<string, NeighborTally>();
18	  for (const liveCell of liveCells) {
19	    for (const candidate of neighborsOf(liveCell)) {
20	      const key = cellKey(candidate);
21	      const existing = tallies.get(key);
22	      if (existing) {
23	        existing.liveNeighborCount += 1;
24	      } else {
25	        tallies.set(key, { cell: candidate, liveNeighborCount: 1 });
26	      }
27	    }
28	  }
29	  return tallies;
30	};
31	
32	const survives = (liveNeighborCount: number): boolean =>
33	  liveNeighborCount === 2 || liveNeighborCount === 3;
34	const isBorn = (liveNeighborCount: number): boolean => liveNeighborCount === 3;
35	
36	export function nextGeneration(cells: Cell[]): Cell[] {
37	  const liveKeys = new Set(cells.map(cellKey));
38	  const tallies = tallyLiveNeighborsPerCandidate(cells);
39	
40	  const nextGen: Cell[] = [];
41	  for (const [key, { cell, liveNeighborCount }] of tallies) {
42	    const wasAlive = liveKeys.has(key);
43	    const willBeAlive = wasAlive ? survives(liveNeighborCount) : isBorn(liveNeighborCount);
44	    if (willBeAlive) {
45	      nextGen.push(cell);
46	    }
47	  }
48	  return nextGen;
49	}
